INSERT INTO public.strategy_iterations (id, concept_id, version, spec_json, parent_iteration_id, status, created_at, created_by, spec_hash, type, import_path, description, is_favorite, updated_at, version_name, is_doc_favorite) VALUES (1, 1, 1, '{"rules": {"exit": null, "entry": {"blocks": [{"conditions": [{"op": "==", "lhs": "indicator:supertrend:direction", "rhs": 1, "lhs_shift": 1}]}, {"is_short": true, "conditions": [{"op": "==", "lhs": "indicator:supertrend:direction", "rhs": -1, "lhs_shift": 1}]}]}}, "indicators": {"supertrend": {"tf": "4h", "low": "low", "high": "high", "close": "close", "period": 10, "indicator": "vbt:SUPERTREND", "multiplier": 3.0}}}', NULL, 'active', '2026-06-21 21:48:20.771116', NULL, NULL, 'generic', NULL, 'Simpler Supertrend  Long/Short-Reversal: Entry Long wenn Supertrend-Direction auf Long dreht; dreht die Direction auf Short, schließt die Long-Position und eröffnet Short (und umgekehrt) via upon_opposite_entry=Reverse.', 'f', '2026-06-25 08:33:06.675867', 'Supertrend 4h Long/Short-Reversal', 'f');
